module hazard_detection_unit
(
	input		[2:0]		src1_check,		
	input		[2:0]		decoding_op_src2,		
	input		[2:0]		ex_op_dest,				
	input		[2:0]		mem_op_dest,			
	input		[2:0]		wb_op_dest,				
	output	reg				pipeline_stall_n		
);
	always @ (*) begin
		pipeline_stall_n = 1;
		if( src1_check != 0 &&
			(
				src1_check == ex_op_dest	||
				src1_check == mem_op_dest	||
				src1_check == wb_op_dest	
			)
		)
			pipeline_stall_n = 0;
		if( decoding_op_src2 != 0 &&
			(
				decoding_op_src2 == ex_op_dest	||
				decoding_op_src2 == mem_op_dest	||
				decoding_op_src2 == wb_op_dest	
			)
		)
			pipeline_stall_n = 0;
	end
endmodule
